import numpy as np

def augment_img(img: np.ndarray, mode: int) -> np.ndarray:
    """
    Apply augmentation to a 2‑D image based on the given mode.

    Parameters
    ----------
    img : np.ndarray
        2‑D array representing the image.
    mode : int
        Integer in the range [0, 7] that selects the transformation.

    Returns
    -------
    np.ndarray
        The transformed image. If ``img`` is empty or not 2‑D, the original
        ``img`` is returned unchanged.
    """
    # Guard clauses – empty or not a 2‑D array
    if img.size == 0 or img.ndim != 2:
        return img

    # Helper for flipping upside‑down
    flip = lambda a: np.flipud(a)

    # Mapping of mode to transformation
    if mode == 0:
        return img
    elif mode == 1:
        return np.rot90(flip(img), k=1)
    elif mode == 2:
        return flip(img)
    elif mode == 3:
        return np.rot90(img, k=3)
    elif mode == 4:
        return np.rot90(flip(img), k=2)
    elif mode == 5:
        return np.rot90(img, k=1)
    elif mode == 6:
        return np.rot90(img, k=2)
    elif mode == 7:
        return np.rot90(flip(img), k=3)
    else:
        # If an unsupported mode is supplied, fall back to the original image
        return img


